#![expect(
    clippy::expect_used,
    clippy::unwrap_used,
    reason = "integration tests use expect/unwrap for assertion clarity"
)]
//! Behavioural tests: `cf_status` returns a typed `StatusSummary`.
//!
//! Slice: state_view — cf_status structured output.
//!
//! The conductor must be able to deserialise the response into a typed
//! structure regardless of kernel version, so the shape is part of the public
//! contract — not a raw blob.
//!
//! Three focused scenarios, one assertion per test:
//!
//! 1. The response JSON round-trips through `StatusSummary` (shape contract).
//! 2. A development-phase ready count is reflected correctly.
//! 3. An abandoned item appears as a distinct `abandoned` count (not dropped,
//!    not folded into `done`).

use cfk_core::types::ids::WorkItemId;
use cfk_core::types::phase::PhaseKind;
use cfk_core::types::routing::WorkType;
use cfk_engine::events::{FactoryEvent, append_event};
use cfk_engine::forge::MemoryForge;
use cfk_mcp::server::{BacklogAddParams, CfkServer, InitParams, PhaseFilterParams};
use rmcp::handler::server::wrapper::Parameters;
use rmcp::model::{CallToolResult, RawContent};
use serde::Deserialize;
use std::sync::Arc;
use tempfile::TempDir;

// ── Semantic response types ───────────────────────────────────────────────────
//
// These are the types the conductor pins to. The production `cf_status`
// handler must emit JSON that round-trips through these exact fields.

/// Per-phase counts in a status dashboard entry.
///
/// `abandoned` is distinct from `done` — items abandoned mid-flight must be
/// surfaced so the conductor can decide whether to requeue them.
#[derive(Debug, Deserialize, PartialEq, Eq)]
pub struct PhaseStatusCounts {
    /// Snake-case phase name (matches `PhaseKind` serde representation).
    pub phase: String,
    /// Items ready to be claimed and worked.
    pub ready: usize,
    /// Items currently claimed and in flight.
    pub in_progress: usize,
    /// Items completed and accepted.
    pub done: usize,
    /// Items that were abandoned before completion.
    pub abandoned: usize,
}

/// Typed status summary — the full response contract for `cf_status`.
#[derive(Debug, Deserialize)]
pub struct StatusSummary {
    /// Project identifier for correlation and display.
    pub project_id: String,
    /// One entry per phase that has at least one work item.
    pub phases: Vec<PhaseStatusCounts>,
}

// ── Test helpers ──────────────────────────────────────────────────────────────

fn make_server(dir: &TempDir) -> CfkServer {
    CfkServer::load_with_forge(dir.path().to_path_buf(), MemoryForge::new())
        .expect("server load should succeed on empty directory")
}

fn make_server_with_forge(dir: &TempDir, forge: Arc<dyn cfk_engine::forge::ForgeAdapter>) -> CfkServer {
    CfkServer::load_with_forge(dir.path().to_path_buf(), forge)
        .expect("server load should succeed")
}

fn is_error(result: &CallToolResult) -> bool {
    result.is_error.unwrap_or(false)
}

fn result_text(result: &CallToolResult) -> String {
    result
        .content
        .iter()
        .filter_map(|c| {
            if let RawContent::Text(t) = &c.raw {
                Some(t.text.as_str())
            } else {
                None
            }
        })
        .collect::<Vec<_>>()
        .join("")
}

async fn init_project(server: &CfkServer, dir: &TempDir) {
    let result = server
        .cf_init(Parameters(InitParams {
            project_root: Some(dir.path().to_str().unwrap().to_string()),
        }))
        .await
        .expect("cf_init should not return McpError");
    assert!(!is_error(&result), "cf_init failed: {}", result_text(&result));
}

async fn add_work_item(server: &CfkServer, phase: PhaseKind, work_type: WorkType, description: &str) -> String {
    let result = server
        .cf_backlog_add(Parameters(BacklogAddParams {
            phase,
            work_type,
            description: description.to_string(),
        }))
        .await
        .expect("cf_backlog_add should not return McpError");
    assert!(!is_error(&result), "cf_backlog_add failed: {}", result_text(&result));
    let raw = result_text(&result);
    let v: serde_json::Value = serde_json::from_str(&raw).expect("backlog_add response is valid JSON");
    v["work_item_id"].as_str().expect("work_item_id present").to_string()
}

async fn call_cf_status(server: &CfkServer) -> StatusSummary {
    let result = server
        .cf_status(Parameters(PhaseFilterParams { phase: None }))
        .await
        .expect("cf_status should not return McpError");
    assert!(!is_error(&result), "cf_status returned a tool error: {}", result_text(&result));
    let raw = result_text(&result);
    serde_json::from_str(&raw)
        .unwrap_or_else(|e| panic!("cf_status response did not deserialise into StatusSummary: {e}\nRaw: {raw}"))
}

// ── Scenario 1: shape contract ────────────────────────────────────────────────
//
// Given: a project with at least one work item
// When:  cf_status is called
// Then:  the response JSON deserialises into StatusSummary
//        (i.e. every phase entry carries exactly the fields: phase, ready,
//         in_progress, done, abandoned — no `blocked` field)
#[tokio::test]
async fn cf_status_response_deserialises_into_status_summary() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;

    add_work_item(
        &server,
        PhaseKind::Development,
        WorkType::OuterBehavioralTestWriting,
        "Some slice",
    )
    .await;

    let result = server
        .cf_status(Parameters(PhaseFilterParams { phase: None }))
        .await
        .expect("cf_status should not return McpError");
    assert!(!is_error(&result), "cf_status returned a tool error: {}", result_text(&result));

    let raw = result_text(&result);
    assert!(!raw.is_empty(), "cf_status response must not be empty");

    let v: serde_json::Value = serde_json::from_str(&raw)
        .unwrap_or_else(|e| panic!("cf_status response is not valid JSON: {e}\nRaw: {raw}"));

    let phases = v["phases"].as_array().expect("'phases' must be an array");
    assert!(!phases.is_empty(), "phases array must not be empty after adding a work item");

    for entry in phases {
        let obj = entry.as_object().expect("each phase entry must be a JSON object");
        assert!(
            obj.contains_key("abandoned"),
            "phase entry must contain 'abandoned' field; got keys: {:?}",
            obj.keys().collect::<Vec<_>>()
        );
        assert!(
            !obj.contains_key("blocked"),
            "phase entry must NOT contain legacy 'blocked' field; got keys: {:?}",
            obj.keys().collect::<Vec<_>>()
        );
    }

    let _: StatusSummary = serde_json::from_str(&raw)
        .unwrap_or_else(|e| panic!("cf_status response did not deserialise into StatusSummary: {e}\nRaw: {raw}"));
}

// ── Scenario 2: ready count ───────────────────────────────────────────────────
//
// Given: a project with 2 Development work items in Ready status
// When:  cf_status is called
// Then:  the Development phase entry reports ready=2
#[tokio::test]
async fn cf_status_development_phase_shows_ready_count() {
    let dir = TempDir::new().expect("tempdir");
    let server = make_server(&dir);
    init_project(&server, &dir).await;

    for description in ["Implement login slice", "Implement logout slice"] {
        add_work_item(
            &server,
            PhaseKind::Development,
            WorkType::OuterBehavioralTestWriting,
            description,
        )
        .await;
    }

    let summary = call_cf_status(&server).await;

    let dev_entry = summary
        .phases
        .iter()
        .find(|p| p.phase == "development")
        .unwrap_or_else(|| {
            panic!(
                "StatusSummary.phases must contain a 'development' entry; got: {:?}",
                summary.phases.iter().map(|p| &p.phase).collect::<Vec<_>>()
            )
        });

    assert_eq!(
        dev_entry.ready, 2,
        "development phase must report ready=2 after adding 2 ready work items"
    );
}

// ── Scenario 3: abandoned count ───────────────────────────────────────────────
//
// Given: a project with a work item that has been driven into Abandoned status
// When:  cf_status is called
// Then:  the relevant phase entry reports abandoned=1 (not folded into done,
//        not dropped, not counted as blocked)
#[tokio::test]
async fn cf_status_abandoned_items_appear_as_distinct_abandoned_count() {
    let dir = TempDir::new().expect("tempdir");

    let setup_forge = MemoryForge::new();
    let setup_server = make_server_with_forge(&dir, setup_forge);
    init_project(&setup_server, &dir).await;

    add_work_item(
        &setup_server,
        PhaseKind::Development,
        WorkType::OuterBehavioralTestWriting,
        "Slice that stays ready",
    )
    .await;

    let work_item_id_str = add_work_item(
        &setup_server,
        PhaseKind::Development,
        WorkType::OuterBehavioralTestWriting,
        "Slice to be abandoned",
    )
    .await;

    let work_item_uuid = uuid::Uuid::parse_str(&work_item_id_str)
        .expect("work_item_id must be a valid UUID");
    let work_item_id: WorkItemId = WorkItemId::try_new(work_item_uuid)
        .expect("work_item_id UUID must be valid");

    let abandon_seq: u64 = {
        let event_dir = cfk_engine::store::event_export_dir(dir.path());
        std::fs::read_dir(&event_dir)
            .expect("event dir must exist after init + backlog_add")
            .filter_map(std::result::Result::ok)
            .count() as u64
            + 1
    };

    append_event(
        dir.path(),
        abandon_seq,
        FactoryEvent::WorkItemAbandoned { work_item_id },
    )
    .expect("append_event must succeed");

    let observe_forge = MemoryForge::new();
    let observe_server = make_server_with_forge(&dir, observe_forge);

    let summary = call_cf_status(&observe_server).await;

    let dev_entry = summary
        .phases
        .iter()
        .find(|p| p.phase == "development")
        .unwrap_or_else(|| {
            panic!(
                "StatusSummary.phases must contain a 'development' entry after adding a work item; got: {:?}",
                summary.phases.iter().map(|p| &p.phase).collect::<Vec<_>>()
            )
        });

    assert_eq!(
        dev_entry.abandoned, 1,
        "development phase must report abandoned=1 after a work item is abandoned; \
         abandoned items must not be silently dropped or folded into 'done'"
    );

    assert_eq!(
        dev_entry.done, 0,
        "abandoned items must NOT be counted as done"
    );
}
